function E = propagate_bp(wavelength,E,L,varargin)% PROPAGATE (Back)Propagates pulse through material%     PROPAGATE(WAVELENGTH,E,LENGTH,MATERIAL,DIRECTION,POLARIZATION,UNITS)%     returns the complex electric field of an input field E with a given%     POLARIZATION going through a MATERIAL of length L (given in UNITS), as%     a function of WAVELENGTH (in nm). DIRECTION = +1 is forward%     propagation, and DIRECTION = -1 is backwards propagation.% % Note that WAVELENGTH must be in nm.% The default values are:% MATERIAL = 'BK7'% DIRECTION = 1% POLARIZATION = 'O'% UNITS = 'mm'%   v1.0, 12/19/01, Patrick O'Shea <pat@socrates.gatech.edu>% Edited by Nicholas Fasano 11/25/2019error(nargchk(3,7,nargin))[material,direction,polarization,u] = ParseVarargin_bp(varargin,'BK7',1,'O','mm');[x,b] = units(u);if b~='m'    error(['The base unit should be m, not ' b '.'])end% L is initially in mm and gets converted to nm  L = L * x / units('nm');% wavelength is still in nmn = refindex_bp(wavelength, material, polarization, 'nm');% % figure, plot(wavelength,n)% % hold on% % title('n vs \lambda')figure(1000), plot(wavelength,abs(E).^2)hold ontitle('Spectrum Vs \lambda')knl = L*n.*2.*pi./wavelength; % dimensionless% % figure, plot(wavelength,knl)% % hold on% % title('n vs \lambda')if isrow(E)    E = E.*exp(-1*direction*1i.*knl);else    E = E.'; knl = knl.';    E = E.*exp(-1.*direction.*1i.*knl);    E = E.'; knl = knl.';endfigure(1000)plot(wavelength,abs(E).^2)E = fftc(center(ifftc(E),'max'));figure(1000)plot(wavelength,abs(E).^2)legend('Input','After propagate','After  fft')